member.example:
Bind the CanvasGroup interactable property using a serialized binder field — the target CanvasGroup is assigned in the Inspector.

    [View]
    public partial class ExampleView
    {
        [SerializeField]
        private CanvasGroupInteractableBinder _interactable;
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public bool _interactable;
    }


Bind the CanvasGroup interactable property by constructing the binder in code.

    [View]
    public partial class ExampleView
    {
        [SerializeField] private CanvasGroup _canvasGroup;
        
        private CanvasGroupInteractableBinder Interactable =>
            new(_canvasGroup);
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public bool _interactable;
    }
